import React, { useState, useEffect } from 'react';
import { Link, NavLink, useLocation } from 'react-router-dom';
import './Navbar.css';

const NAV_ITEMS = [
  { label: 'Home', path: '/' },
  {
    label: 'Events',
    children: [
      { label: 'Upcoming Fashion Show', path: '/upcoming-show' },
      { label: 'Model Screening', path: '/model-screening' },
      { label: "Designer's Meet", path: '/designers-meet' },
      { label: 'Upcoming Workshop', path: '/workshop' },
    ],
  },
  {
    label: 'Services',
    children: [
      { label: 'Become a Model', path: '/become-a-model' },
      { label: 'Hire a Model', path: '/hire-a-model' },
      { label: 'Portfolio Service', path: '/portfolio' },
    ],
  },
  { label: 'Contact', path: '/contact' },
];

export default function Navbar() {
  const [scrolled, setScrolled]     = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);
  const [openDrop, setOpenDrop]     = useState(null);
  const location = useLocation();

  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > 60);
    window.addEventListener('scroll', fn);
    return () => window.removeEventListener('scroll', fn);
  }, []);

  useEffect(() => {
    setMobileOpen(false);
    setOpenDrop(null);
  }, [location]);

  return (
    <>
      {/* Top alert bar */}
      <div className="nav-topbar">
        <span className="nav-topbar__marquee">
          ✦ Registrations Open for Model Screening-II &nbsp;|&nbsp; Designer's Meet-II &nbsp;|&nbsp; Limited Seats &mdash; Apply Now!
        </span>
        <div className="nav-topbar-right">
          <a href="https://wa.me/917290081087" target="_blank" rel="noreferrer" className="nav-topbar__wa">
            <svg width="14" height="14" viewBox="0 0 24 24" fill="currentColor"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z"/></svg>
            WhatsApp
          </a>
          <a href="tel:+917290081087">📞 +91 72900 81087</a>
          <a href="mailto:info@fashionrunway.in">✉️ info@fashionrunway.in</a>
        </div>
      </div>

      <header className={`navbar ${scrolled ? 'navbar--scrolled' : ''}`}>
        <div className="navbar__inner container">

          {/* Logo */}
          <Link to="/" className="navbar__logo">
            <span className="logo-icon">✦</span>
            <div className="logo-text">
              <span className="logo-main">Fashion Runway</span>
              <span className="logo-sub">Event Management</span>
            </div>
          </Link>

          {/* Desktop nav */}
          <nav className="navbar__nav">
            {NAV_ITEMS.map((item) =>
              item.children ? (
                <div
                  key={item.label}
                  className="nav-item nav-item--dropdown"
                  onMouseEnter={() => setOpenDrop(item.label)}
                  onMouseLeave={() => setOpenDrop(null)}
                >
                  <span className="nav-link nav-link--drop">
                    {item.label} <span className="drop-arrow">▾</span>
                  </span>
                  {openDrop === item.label && (
                    <div className="dropdown">
                      {item.children.map((c) => (
                        <NavLink key={c.path} to={c.path} className="dropdown__item">
                          {c.label}
                        </NavLink>
                      ))}
                    </div>
                  )}
                </div>
              ) : (
                <NavLink
                  key={item.path}
                  to={item.path}
                  end={item.path === '/'}
                  className={({ isActive }) => `nav-link${isActive ? ' nav-link--active' : ''}`}
                >
                  {item.label}
                </NavLink>
              )
            )}
          </nav>

          {/* CTA */}
          <Link to="/model-screening" className="btn btn-gold navbar__cta">
            Quick Apply
          </Link>

          {/* Hamburger */}
          <button
            className={`hamburger ${mobileOpen ? 'open' : ''}`}
            onClick={() => setMobileOpen(!mobileOpen)}
            aria-label="Menu"
          >
            <span /><span /><span />
          </button>
        </div>

        {/* Mobile menu */}
        {mobileOpen && (
          <div className="mobile-menu">
            {NAV_ITEMS.map((item) =>
              item.children ? (
                <div key={item.label}>
                  <button
                    className="mobile-menu__group-btn"
                    onClick={() => setOpenDrop(openDrop === item.label ? null : item.label)}
                  >
                    {item.label} <span>{openDrop === item.label ? '▴' : '▾'}</span>
                  </button>
                  {openDrop === item.label && (
                    <div className="mobile-menu__sub">
                      {item.children.map((c) => (
                        <NavLink key={c.path} to={c.path} className="mobile-menu__link mobile-menu__link--sub">
                          {c.label}
                        </NavLink>
                      ))}
                    </div>
                  )}
                </div>
              ) : (
                <NavLink key={item.path} to={item.path} end={item.path === '/'} className="mobile-menu__link">
                  {item.label}
                </NavLink>
              )
            )}
            <Link to="/model-screening" className="btn btn-gold" style={{ marginTop: 12 }}>
              Quick Apply
            </Link>
          </div>
        )}
      </header>
    </>
  );
}
